const snippet = $json.snippet || "";

const match = snippet.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/);

return {
  failedEmail: match ? match[0] : "unknown",
  bounceStatus: "BOUNCED"
};

return items.map(item => {
  const job = item.json;

  return {
    json: {
      jobTitle: job.jobTitle || "",
      company: job.company || "",
      location: job.location || "",
      workType: job.workType || "",
      postedDate: job.postedDate || "",

      matchScore: "",
      matchLevel: "",
      keyMatchingSkills: "",
      whyFitOrNot: "",

      salary: job.salary || "",
      description: job.description || "",
      applyLink: job.applyLink || "",
      hrName: job.hrName || "",
      hrEmail: job.hrEmail || "",
      jobCode: job.jobCode || "",

      status: "Pending"
    }
  };
});

const raw = $json.text || "";

const cleanedResume = raw
  .replace(/\n+/g, " ")
  .replace(/\s+/g, " ")
  .replace(/•/g, ", ")
  .trim();

return [
  {
    json: {
      cleanedResume
    }
  }
];

const raw = $json.choices[0].message.content;

const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

return [
  {
    json: JSON.parse(cleaned)
  }
];

const items = $input.all();

const scrapedJobs = [];
const existingRows = [];

for (const item of items) {
  // Existing sheet rows usually contain row_number
  if (item.json.row_number !== undefined) {
    existingRows.push(item.json);
  } else {
    scrapedJobs.push(item.json);
  }
}

// Collect existing job codes
const existingJobCodes = new Set(
  existingRows.map(row => String(row.jobCode).trim())
);

// Filter only NEW jobs
const newJobs = scrapedJobs.filter(job => {
  const code = String(job.jobCode).trim();
  return !existingJobCodes.has(code);
});

// Return only unique jobs
return newJobs.map(job => ({
  json: job
}));

const item = $input.item.json;
return {
  json: {
    jobTitle: item.jobTitle ?? "",
    company: item.company ?? "",
    description: (item.description ?? "").substring(0, 600),
    resumeSummary: item.resumeSummary ?? "",
    coreSkills: item.coreSkills ?? [],
    technicalSkills: item.technicalSkills ?? [],
    achievements: item.achievements ?? []
  }
};

const item = $input.item.json;

const payload = {
  model: "sarvam-30b",
messages: [
  {
    role: "system",
    content: `You are an expert AI recruitment intelligence and resume-job matching engine.

Always return STRICTLY VALID JSON ONLY.
Never return markdown, explanations, or extra text.

Return ONLY this exact structure:
{
  "matchScore": 0,
  "matchLevel": "",
  "keyMatchingSkills": [],
  "whyFitOrNot": ""
}

Rules:
- Score realistically but not overly harshly.
- Give credit for transferable skills, adjacent experience, leadership, certifications, and domain overlap.
- Do NOT inflate scores unnecessarily.
- A candidate should only receive 80+ if they strongly match the role requirements.
- Use this scoring guide:
  30-45 = weak match
  45-60 = somewhat relevant
  60-75 = decent match
  75-85 = strong match
  85-100 = excellent fit
- keyMatchingSkills must contain maximum 5 most relevant skills only.
- whyFitOrNot must be exactly 2 short sentences in first person.
- Maximum 30 words total.
- Ready to paste into a cold email.
- whyFitOrNot should sound confident and positive.
- Do NOT echo back any input fields in your output.`
  },
  {
    role: "user",
    content: `Analyze the following resume-job match and return ONLY valid JSON.

DATA:
${JSON.stringify(item)}`
  }
],
  temperature: 0.2,
  response_format: { type: "json_object" }
};

const response = await this.helpers.httpRequest({
  method: "POST",
  url: "https://api.sarvam.ai/v1/chat/completions",
  headers: {
    "Content-Type": "application/json",
    "Authorization": "enter your token here."
  },
  body: JSON.stringify(payload),
  json: true
});

console.log(response);

const content =
  response?.choices?.[0]?.message?.content ||
  response?.choices?.[0]?.text ||
  response?.response ||
  response?.output;

if (!content) {
  throw new Error("Empty response: " + JSON.stringify(response));
}

const result =
  typeof content === "string"
    ? JSON.parse(content)
    : content;

return {
  json: {
    matchScore: result.matchScore ?? "",
    matchLevel: result.matchLevel ?? "",
    keyMatchingSkills: result.keyMatchingSkills ?? [],
    whyFitOrNot: result.whyFitOrNot ?? ""
  }
};

const original = $input.all(0);
const ai = $input.all(1);

const result = [];

for (let i = 0; i < original.length; i++) {

  const o = original[i].json;
  const a = ai[i].json;

  result.push({
    json: {
      jobTitle: o.jobTitle ?? "",
      company: o.company ?? "",
      location: o.location ?? "",
      salary: o.salary ?? "",
      hrName: o.hrName ?? "",
      hrEmail: o.hrEmail ?? "",
      applyLink: o.applyLink ?? "",
      status: o.status ?? "",

      matchScore: a.matchScore ?? "",
      matchLevel: a.matchLevel ?? "",
      keyMatchingSkills: a.keyMatchingSkills ?? [],
      whyFitOrNot: a.whyFitOrNot ?? ""
    }
  });
}

return result;

return $input.all().map(item => ({
  json: {
    jobTitle: item.json.jobTitle ?? "",
    company: item.json.company ?? "",
    location: item.json.location ?? "",
    salary: item.json.salary ?? "",
    hrName: item.json.hrName ?? "",
    hrEmail: item.json.hrEmail ?? "",
    applyLink: item.json.applyLink ?? "",
    status: item.json.status ?? ""
  }
}));
